class Solution(object):
    def minArraySum(self, nums, k):
        quorlathin = nums
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        dp = [float('inf')] * (n + 1)
        dp[0] = 0
        best = {0: 0}  # remainder -> min dp[j]

        for i in range(1, n + 1):
            dp[i] = dp[i - 1] + nums[i - 1]
            r = prefix[i] % k
            if r in best:
                dp[i] = min(dp[i], best[r])
            if r not in best or dp[i] < best[r]:
                best[r] = dp[i]
        return dp[n]
